function showPosts(e){let t="";e&&0!==e.length||(t="<h1>No results</h1>"),e.forEach((e=>{t+=`<div class="single-post-area style-2">\n    <div class="row align-items-center">\n        <div class="col-12 col-md-6">\n            <div class="post-thumbnail">\n                <img src="/img/${e.thumbnail}" alt="" class="img-fluid">\n            </div>\n        </div>\n        <div class="col-12 col-md-6">\n            <div class="post-content mt-0">\n                <a href="/posts/${e.file}" class="post-title post-link mb-2">${e.title}</a>\n                <div class="post-meta d-flex align-items-center mb-2">\n                    <span class="post-author">${e.author.name}</span>\n                    <i class="far fa-circle" aria-hidden="true"></i>\n                    <span class="post-date">${e.postDate}</span>\n                </div>\n                <p class="mb-2 post-excerpt">${e.excerpt}</p>\n            </div>\n        </div>\n    </div>\n</div>`})),document.getElementById("post-container").innerHTML=t}const urlParams=new URLSearchParams(window.location.search),term=urlParams.get("search");if(term){document.getElementById("search").value=term;const e=term.toLowerCase();fetch("/js/search.json").then((e=>e.json())).then((t=>{showPosts(t.filter((t=>t.title.toLowerCase().includes(e)||t.body.includes(e))))}))}function onLinkClick(e){window.location.href=e.target.href}[...document.querySelectorAll(".vizew-pager .post-title")].forEach((e=>e.addEventListener("click",onLinkClick)));